import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import { useLanguage } from '../contexts/LanguageContext';
import { getKeyboardConfig } from '../config/keyboardLoader';
import VirtualKeyboard from '../components/VirtualKeyboard';
import './Lesson.css';

// ── e.code → lowercase physical key ──────────────────────────────────────────
const CODE_TO_KEY = {
  KeyA:'a', KeyB:'b', KeyC:'c', KeyD:'d', KeyE:'e', KeyF:'f', KeyG:'g',
  KeyH:'h', KeyI:'i', KeyJ:'j', KeyK:'k', KeyL:'l', KeyM:'m', KeyN:'n',
  KeyO:'o', KeyP:'p', KeyQ:'q', KeyR:'r', KeyS:'s', KeyT:'t', KeyU:'u',
  KeyV:'v', KeyW:'w', KeyX:'x', KeyY:'y', KeyZ:'z',
  Semicolon:';', Quote:"'", Comma:',', Period:'.', Slash:'/',
  BracketLeft:'[', BracketRight:']', Backslash:'\\', Backquote:'`',
  Digit1:'1', Digit2:'2', Digit3:'3', Digit4:'4', Digit5:'5',
  Digit6:'6', Digit7:'7', Digit8:'8', Digit9:'9', Digit0:'0',
  Minus:'-', Equal:'=', Space:' ',
};

// ── Split content into displayable chunks ────────────────────────────────────
const splitIntoLines = (text, lessonType) => {
  if (lessonType === 'paragraph') {
    const sentences = text.split(/(?<=[.!?।])\s+/).map(s => s.trim()).filter(Boolean);
    const chunks = [];
    for (let i = 0; i < sentences.length; i += 5)
      chunks.push(sentences.slice(i, i + 5).join(' '));
    return chunks.length > 0 ? chunks : [text];
  }
  if (lessonType === 'sentences') {
    const sentences = text.split(/(?<=[.!?।])\s+/).map(s => s.trim()).filter(Boolean);
    return sentences.length > 0 ? sentences : [text];
  }
  const words = text.trim().split(/\s+/);
  const chunks = [];
  for (let i = 0; i < words.length; i += 10)
    chunks.push(words.slice(i, i + 10).join(' '));
  return chunks;
};

const Lesson = () => {
  const { chapterId, lessonId } = useParams();
  const navigate = useNavigate();

  // ── Language & keyboard config ───────────────────────────────────────────
  const { language } = useLanguage();
  const { layout } = getKeyboardConfig(language);

  // Build physical-key → Gurmukhi char maps from the layout (Punjabi only)
  const { keyMap, shiftMap } = useMemo(() => {
    const km = {}, sm = {};
    if (language === 'punjabi') {
      layout.forEach(row => row.forEach(entry => {
        if (typeof entry === 'object' && entry.key) {
          if (entry.display && !['Tab','CapsLock','Backspace','Enter','⌫','↵','⇧','Space'].includes(entry.display))
            km[entry.key] = entry.display;
          if (entry.shift && entry.shift.length <= 3)
            sm[entry.key] = entry.shift;
        }
      }));
      // Space always maps to space
      km[' '] = ' ';
    }
    return { keyMap: km, shiftMap: sm };
  }, [language, layout]);

  // ── Lesson data ──────────────────────────────────────────────────────────
  const [lessonData, setLessonData] = useState(null);
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState(null);

  // ── Line-by-line state ───────────────────────────────────────────────────
  const [lines, setLines]         = useState([]);
  const [lineIndex, setLineIndex] = useState(0);
  const [charIndex, setCharIndex] = useState(0);
  const [wrongChar, setWrongChar] = useState(false);
  const [linePhase, setLinePhase] = useState('visible');

  // ── Global stats ─────────────────────────────────────────────────────────
  const [errors, setErrors]     = useState(0);
  const [userInput, setUserInput] = useState('');
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isComplete, setIsComplete]   = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [lastKeyCorrect, setLastKeyCorrect] = useState(null);

  const inputRef  = useRef(null);
  const timerRef  = useRef(null);
  const startRef  = useRef(null);
  const errorsRef = useRef(0);
  const charsRef  = useRef(0);

  // ── Load lesson ──────────────────────────────────────────────────────────
  useEffect(() => {
    const fetchLesson = async () => {
      try {
        const res = await chaptersAPI.getLesson(chapterId, lessonId);
        const data = res.data;
        setLessonData(data);
        setLines(splitIntoLines(data.lesson.content, data.lesson.lessonType));
      } catch {
        setError('Failed to load lesson');
      } finally {
        setLoading(false);
      }
    };
    fetchLesson();
    return () => clearInterval(timerRef.current);
  }, [chapterId, lessonId]);

  useEffect(() => {
    if (!isComplete && inputRef.current) inputRef.current.focus();
  }, [isComplete, lineIndex]);

  // ── Timer ────────────────────────────────────────────────────────────────
  const startTimer = () => {
    if (startRef.current) return;
    startRef.current = Date.now();
    timerRef.current = setInterval(() =>
      setTimeElapsed(Math.floor((Date.now() - startRef.current) / 1000)), 500);
  };

  const calcWpm = () => {
    if (!startRef.current || charsRef.current === 0) return 0;
    const mins = (Date.now() - startRef.current) / 60000;
    return mins < 0.01 ? 0 : Math.round((charsRef.current / 5) / mins);
  };

  // ── Submit ───────────────────────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    clearInterval(timerRef.current);
    const elapsed = startRef.current ? Math.round((Date.now() - startRef.current) / 1000) : 0;
    setTimeElapsed(elapsed);
    const mins = elapsed / 60 || 0.1;
    const wpm  = Math.round((charsRef.current / 5) / mins);
    const totalLen = lines.join(' ').length || 1;
    const accuracy = Math.max(0, Math.round(((totalLen - errorsRef.current) / totalLen) * 100));
    try { await progressAPI.submitLesson({ chapterId, lessonId, wpm, accuracy }); }
    catch (e) { console.error('Submit failed', e); }
    setIsComplete(true);
    setShowResults(true);
  }, [chapterId, lessonId, lines]);

  // ── Line transition ───────────────────────────────────────────────────────
  const advanceToNextLine = useCallback(() => {
    setLinePhase('fadeout');
    setTimeout(() => {
      const next = lineIndex + 1;
      if (next >= lines.length) { handleSubmit(); return; }
      setLineIndex(next);
      setCharIndex(0);
      setUserInput('');
      setWrongChar(false);
      setLinePhase('fadein');
      setTimeout(() => setLinePhase('visible'), 250);
    }, 280);
  }, [lineIndex, lines.length, handleSubmit]);

  // ── Core char-by-char logic (shared between English & Punjabi) ───────────
  const processChar = useCallback((typedChar, currentLine) => {
    if (!startRef.current) startTimer();
    // Use Array.from for proper Unicode char splitting (handles Gurmukhi)
    const chars = [...currentLine];
    const expectedChar = chars[charIndex];

    if (typedChar !== expectedChar) {
      errorsRef.current += 1;
      setErrors(errorsRef.current);
      setWrongChar(true);
      setLastKeyCorrect(false);
      return;
    }

    setWrongChar(false);
    setLastKeyCorrect(true);
    charsRef.current += 1;
    const newCharIndex = charIndex + 1;
    setCharIndex(newCharIndex);
    if (newCharIndex >= chars.length) advanceToNextLine();
  }, [charIndex, advanceToNextLine]);

  // ── handleInputChange (English / paragraph mode) ─────────────────────────
  const handleInputChange = (e) => {
    if (linePhase !== 'visible' || isComplete) return;
    const value = e.target.value;
    const currentLine = lines[lineIndex] || '';
    const isParagraph = lessonData?.lesson?.lessonType === 'paragraph';
    const isDeleting  = value.length < userInput.length;

    if (!startRef.current) startTimer();

    if (isParagraph) { setUserInput(value); return; }

    if (isDeleting) {
      // For Punjabi, trim last Unicode char; for English, trim last char
      const newValue = language === 'punjabi'
        ? [...userInput].slice(0, -1).join('')
        : value;
      setUserInput(newValue);
      setCharIndex(prev => Math.max(0, prev - 1));
      setWrongChar(false);
      setLastKeyCorrect(null);
      return;
    }

    const typedChar = [...value][value.length - 1] ?? '';
    setUserInput(value);
    processChar(typedChar, currentLine);
  };

  // ── handleKeyDown ─────────────────────────────────────────────────────────
  const handleKeyDown = (e) => {
    const isParagraph = lessonData?.lesson?.lessonType === 'paragraph';
    const currentLine = lines[lineIndex] || '';

    // ── Paragraph Enter ───────────────────────────────────────────────────
    if (isParagraph && e.key === 'Enter') {
      e.preventDefault();
      if (linePhase !== 'visible' || !userInput.trim()) return;
      const typed  = userInput.trim();
      const target = currentLine.replace(/\s+$/, '');
      let chunkErrors = 0;
      const maxLen = Math.max([...typed].length, [...target].length);
      const tChars = [...typed], rChars = [...target];
      for (let i = 0; i < maxLen; i++)
        if (tChars[i] !== rChars[i]) chunkErrors++;
      errorsRef.current += chunkErrors;
      setErrors(errorsRef.current);
      charsRef.current += [...currentLine].length;
      advanceToNextLine();
      return;
    }

    // ── Punjabi key interception ──────────────────────────────────────────
    if (language === 'punjabi' && !isParagraph && !e.ctrlKey && !e.altKey && !e.metaKey) {
      // Backspace — remove last Unicode character
      if (e.key === 'Backspace') {
        e.preventDefault();
        if (linePhase !== 'visible' || isComplete) return;
        if (userInput.length === 0) return;
        const newValue = [...userInput].slice(0, -1).join('');
        setUserInput(newValue);
        setCharIndex(prev => Math.max(0, prev - 1));
        setWrongChar(false);
        setLastKeyCorrect(null);
        return;
      }

      // Skip non-printable keys
      const skipKeys = ['Shift','Control','Alt','Meta','CapsLock','Tab','Escape',
        'ArrowLeft','ArrowRight','ArrowUp','ArrowDown','Delete',
        'Home','End','PageUp','PageDown','Enter',
        'F1','F2','F3','F4','F5','F6','F7','F8','F9','F10','F11','F12'];
      if (skipKeys.includes(e.key)) return;

      e.preventDefault();
      if (linePhase !== 'visible' || isComplete) return;

      // Translate physical key → Gurmukhi character
      const physKey = CODE_TO_KEY[e.code] ?? e.key.toLowerCase();
      const punjabiChar = e.shiftKey
        ? (shiftMap[physKey] ?? '')
        : (keyMap[physKey] ?? '');

      if (!punjabiChar) return;

      const newValue = userInput + punjabiChar;
      setUserInput(newValue);
      processChar(punjabiChar, currentLine);
    }
  };

  // ── Render current line ───────────────────────────────────────────────────
  const renderLine = () => {
    const line = lines[lineIndex] || '';
    const isParagraph = lessonData?.lesson?.lessonType === 'paragraph';
    if (isParagraph) return <>{line}<span className="enter-hint">↵</span></>;

    // Use Array.from for proper Unicode char splitting
    return [...line].map((char, i) => {
      let cls = '';
      if (i < charIndex)        cls = 'correct';
      else if (i === charIndex) cls = wrongChar ? 'incorrect' : 'current';
      return <span key={i} className={cls}>{char}</span>;
    });
  };

  const getCurrentKey = () => {
    if (isComplete || !lines[lineIndex]) return null;
    return [...lines[lineIndex]][charIndex] || null;
  };

  // ── Loading / Error ───────────────────────────────────────────────────────
  if (loading) return <div className="loading">Loading lesson...</div>;
  if (error || !lessonData) return (
    <div className="container">
      <div className="error">{error || 'Lesson not found'}</div>
      <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
    </div>
  );

  const { chapter, lesson } = lessonData;
  const showKeyboard  = lesson.lessonType !== 'paragraph';
  const totalChars    = charsRef.current;
  const liveAccuracy  = totalChars > 0 ? Math.round(((totalChars - errors) / totalChars) * 100) : 100;
  const progressPct   = lines.length > 0 ? Math.round((lineIndex / lines.length) * 100) : 0;
  const resultElapsed = timeElapsed;
  const resultWpm     = Math.round((charsRef.current / 5) / (resultElapsed / 60 || 0.1));
  const resultAccuracy = lines.length > 0
    ? Math.max(0, Math.round(((lines.join(' ').length - errorsRef.current) / lines.join(' ').length) * 100))
    : 100;

  return (
    <div className="lesson-container-with-panel">
      <div className="lesson-main-area">

        {/* Header */}
        <div className="lesson-header-compact">
          <h3>Chapter {chapter.chapterNumber} • Lesson {lesson.lessonNumber}</h3>
          <span className="header-divider">|</span>
          <p>{lesson.lessonTitle}</p>
        </div>

        {/* Progress Bar */}
        <div className="line-progress-bar">
          <div className="line-progress-fill" style={{ width: `${progressPct}%` }} />
          <span className="line-counter-inline">Line {lineIndex + 1}/{lines.length}</span>
        </div>

        {/* Target Text */}
        <div className={`typing-content line-${linePhase}`}>
          {renderLine()}
        </div>

        {/* Input */}
        {!isComplete && (
          <textarea
            ref={inputRef}
            className="typing-input"
            value={userInput}
            onChange={language === 'punjabi' ? undefined : handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder={lesson.lessonType === 'paragraph'
              ? 'Type here… press Enter ↵ when done'
              : language === 'punjabi' ? 'ਇੱਥੇ ਟਾਈਪ ਕਰੋ...' : 'Start typing...'}
            autoComplete="off"
            autoCorrect="off"
            autoCapitalize="off"
            spellCheck="false"
            autoFocus
            readOnly={language === 'punjabi' && lesson.lessonType !== 'paragraph'}
          />
        )}

        {/* Virtual Keyboard */}
        {showKeyboard && !isComplete && (
          <VirtualKeyboard activeKey={getCurrentKey()} isCorrect={lastKeyCorrect} />
        )}
      </div>

      {/* Right Panel */}
      {!isComplete && (
        <div className="control-panel-right">
          <div className="control-stat">
            <div className="stat-label">⏱️ TIMER</div>
            <div className="stat-value-large timer-color">{timeElapsed}s</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">✓ ACCURACY</div>
            <div className="stat-value-large accuracy-color">{liveAccuracy}%</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">❌ ERRORS</div>
            <div className="stat-value-large error-color">{errors}</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">⚡ WPM</div>
            <div className="stat-value-large wpm-color">{calcWpm()}</div>
          </div>
          <div className="control-buttons">
            <button className="btn-control btn-submit" onClick={handleSubmit}>Submit</button>
            <button className="btn-control btn-exit" onClick={() => navigate('/learn')}>Exit</button>
          </div>
        </div>
      )}

      {/* Results Modal */}
      {showResults && (
        <div className="results-modal">
          <div className="results-content">
            <h2>Lesson Complete! 🎉</h2>
            <div className="results-stats">
              <div className="result-stat"><h3>{resultWpm}</h3><p>Words Per Minute</p></div>
              <div className="result-stat"><h3>{resultAccuracy}%</h3><p>Accuracy</p></div>
              <div className="result-stat"><h3>{resultElapsed}s</h3><p>Time Taken</p></div>
              <div className="result-stat"><h3>{errorsRef.current}</h3><p>Errors</p></div>
            </div>
            <div className="results-actions">
              <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
              <button className="btn btn-secondary" onClick={() => window.location.reload()}>Try Again</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Lesson;
